public class Order {
    private final List<LineItem> items = new ArrayList<>();
    private Money cachedTotal = Money.ZERO;

    public void add(LineItem item) {
        items.add(item);
        cachedTotal = cachedTotal.plus(item.price());
    }

    public List<LineItem> getItems() {
        return items;
    }

    public Money getTotal() {
        return cachedTotal;
    }
}

